/**
 * Webhook notification adapter.
 *
 * Implements NotificationAdapter for the 'webhook' channel.
 * Formats the notification payload as JSON and POSTs it to a configured URL.
 * Supports configurable transport for testing and custom HTTP clients.
 */

import type { NotificationPayload } from '../models/notification.js';
import type {
  NotificationAdapter,
  NotificationDeliveryResult,
} from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/** A webhook delivery record with metadata. */
export interface SentWebhook {
  url: string;
  payload: WebhookRequestBody;
  sentAt: Date;
  notificationType: string;
}

/** The JSON body sent in the webhook POST request. */
export interface WebhookRequestBody {
  event: string;
  recipient: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  timestamp: string;
}

/** Configuration for the webhook adapter. */
export interface WebhookAdapterConfig {
  /** The URL to POST webhook payloads to. */
  url: string;
  /** Optional transport function — called for actual delivery. Return true for success. */
  transport?: (url: string, body: WebhookRequestBody) => Promise<boolean>;
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private sentWebhooks: SentWebhook[] = [];
  private config: WebhookAdapterConfig;

  constructor(config: WebhookAdapterConfig) {
    this.config = config;
  }

  /**
   * Format a notification payload into a webhook request body.
   */
  formatPayload(payload: NotificationPayload): WebhookRequestBody {
    return {
      event: payload.notificationType,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      metadata: payload.metadata,
      timestamp: new Date().toISOString(),
    };
  }

  /**
   * Send a webhook notification by POSTing JSON to the configured URL.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    try {
      if (!this.config.url) {
        const msg = 'Webhook URL is not configured';
        this.logger.error(msg);
        return { success: false, error: msg };
      }

      const body = this.formatPayload(payload);
      this.logger.info(`Sending webhook to ${this.config.url} for event ${body.event}`);

      if (this.config.transport) {
        const ok = await this.config.transport(this.config.url, body);
        if (!ok) {
          const msg = `Webhook delivery failed for ${this.config.url}`;
          this.logger.error(msg);
          return { success: false, error: msg };
        }
      }

      this.sentWebhooks.push({
        url: this.config.url,
        payload: body,
        sentAt: new Date(),
        notificationType: payload.notificationType,
      });

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Failed to send webhook to ${this.config.url}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all webhooks sent through this adapter. Useful for testing.
   */
  getSentWebhooks(): SentWebhook[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhook history.
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }
}

